// runWork is the RunE for "ddx work". It drives the FEAT-010 layer-3 queue
// drain with harness/provider/model treated as opaque passthrough constraints —
// ValidateForExecuteLoopViaService is not called; DDx does not inspect or
// branch on those values. Retry-power policy (min-power / max-power) is owned
// by this layer.
func (f *CommandFactory) runWork(cmd *cobra.Command, args []string) error {
	if err := f.checkLifecycleMigrationGate(cmd); err != nil {
		return err
	}

	projectFlag, _ := cmd.Flags().GetString("project")
	projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)
	lockmetrics.SetSink(lockmetrics.FileSink(projectRoot))
	lockmetrics.SetCapEnforcement(projectRoot, "")
	f.warnIfInstalledBinaryBehindSource(cmd)

	// Preflight: warn once per process for degraded project-local skill layout.
	// Suppressed in JSON mode to avoid corrupting machine-readable output
	// (stderr and stdout are merged by some test helpers and log aggregators).
	asJSON, _ := cmd.Flags().GetBool("json")
	if !asJSON {
		preflightResult := checkProjectRuntimePreflight(projectRoot)
		f.preflightWarnOnce.Do(func() {
			emitPreflightWarning(cmd.ErrOrStderr(), preflightResult)
		})
	}

	return f.runAgentExecuteLoopImpl(cmd, true, "")
}

func writeExecuteLoopResult(w io.Writer, projectRoot string, result *agent.ExecuteBeadLoopResult, asJSON bool) error {
	if asJSON {
		payload := struct {
			ProjectRoot string `json:"project_root"`
			*agent.ExecuteBeadLoopResult
		}{
			ProjectRoot:           projectRoot,
			ExecuteBeadLoopResult: result,
		}
		enc := json.NewEncoder(w)
		enc.SetIndent("", "  ")
		return enc.Encode(payload)
	}

	if result.NoReadyWork && result.Attempts == 0 {
		writeNoReadyWorkSummary(w, projectRoot, result.NoReadyWorkDetail)
		writeQueueSnapshotTerminalSummary(w, result.QueueSnapshot)
		return nil
	}

	fmt.Fprintf(w, "\nproject: %s\n", projectRoot)
	writeWorkTerminalSummary(w, result)
	writeOperatorAttentionSummary(w, result.OperatorAttention)
	preserved := preservedWorkAttempts(result)
	if len(preserved) > 0 {
		fmt.Fprintf(w, "\npreserved:\n")
		for _, attempt := range preserved {
			fmt.Fprintf(w, "  - %s: %s", attempt.BeadID, attempt.Detail)
			if attempt.PreserveRef != "" {
				fmt.Fprintf(w, " (%s)", attempt.PreserveRef)
			}
			fmt.Fprintln(w)
		}
	}
	failed := failedWorkAttempts(result)
	if len(failed) > 0 {
		fmt.Fprintf(w, "\nfailed:\n")
		for _, attempt := range failed {
			fmt.Fprintf(w, "  - %s: %s", attempt.BeadID, attempt.Detail)
			if attempt.PreserveRef != "" {
				fmt.Fprintf(w, " (preserved)")
			}
			fmt.Fprintln(w)
		}
	}
	if result.NoReadyWork {
		fmt.Fprintln(w)
		writeNoReadyWorkSummary(w, "", result.NoReadyWorkDetail)
		writeQueueSnapshotTerminalSummary(w, result.QueueSnapshot)
	}
	return nil
}

func writeWorkTerminalSummary(w io.Writer, result *agent.ExecuteBeadLoopResult) {
	closed, changed, alreadySatisfied, preserved := countWorkTerminalOutcomes(result)
	fmt.Fprintf(w, "worker exited: %s\n", workExitSummary(result))
	fmt.Fprintf(w, "attempts: %d  |  closed: %d  |  changed: %d  |  already-satisfied: %d  |  preserved: %d  |  failures: %d\n",
		result.Attempts, closed, changed, alreadySatisfied, preserved, result.Failures)
}

func writeOperatorAttentionSummary(w io.Writer, stop *agent.OperatorAttentionStop) {
	if stop == nil {
		return
	}
	fmt.Fprintln(w)
	fmt.Fprintln(w, "operator attention:")
	if stop.BeadID != "" {
		fmt.Fprintf(w, "  released bead: %s\n", stop.BeadID)
	}
	if stop.Message != "" {
		fmt.Fprintf(w, "  %s\n", stop.Message)
	}
	if stop.ProjectRoot != "" {
		fmt.Fprintf(w, "  project root: %s\n", stop.ProjectRoot)
	}
	if len(stop.DirtyPaths) > 0 {
		fmt.Fprintf(w, "  dirty paths: %s\n", strings.Join(stop.DirtyPaths, ", "))
	}
}

	if err != nil {
		if errors.Is(err, os.ErrNotExist) {
			return nil
		}
		return err
	}

	projectRoot := state.ProjectRoot
	if projectRoot == "" {
		projectRoot = s.manager.projectRoot
	}

	active, running, terminals, staleIDs, err := s.snapshotWorkers(projectRoot)
	if err != nil {
		return err
	}

	for _, id := range staleIDs {
		if err := s.manager.stopStaleDiskEntry(id); err != nil {
			return err
		}
	}

	s.recordTerminalHistory(terminals, now)

	if len(active) > state.DesiredCount {
		excess := len(active) - state.DesiredCount
		if err := s.stopNewestExcess(running, excess); err != nil {
			return err
		}
	}

	if len(active) < state.DesiredCount && s.canStartMore(state, now) {
		missing := state.DesiredCount - len(active)
		for i := 0; i < missing; i++ {
			spec := state.DefaultSpec
			spec.ProjectRoot = projectRoot
			if _, err := s.manager.StartExecuteLoop(spec); err != nil {
				return err
			}
		}
	}

	return nil
}

func (s *WorkerSupervisor) snapshotWorkers(projectRoot string) (active []WorkerRecord, running []WorkerRecord, terminals []WorkerRecord, staleIDs []string, err error) {
	if s == nil || s.manager == nil {
		return nil, nil, nil, nil, fmt.Errorf("worker supervisor is not configured")
	}

	entries, err := os.ReadDir(s.manager.rootDir)
	if err != nil {
		return nil, nil, nil, nil, err
	}

	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}

		dir := filepath.Join(s.manager.rootDir, entry.Name())
		rec, readErr := s.manager.readRecord(dir)
		if readErr != nil {
			continue
		}
		if rec.Kind != "work" {
			continue
		}
		if rec.ProjectRoot != "" && rec.ProjectRoot != projectRoot {
			continue
		}

		hasHandle := s.manager.hasWorkerHandle(rec.ID)
		switch rec.State {
		case "running", "stopping":
			if !hasHandle {
				staleIDs = append(staleIDs, rec.ID)
				continue
			}
			active = append(active, rec)
			if rec.State == "running" {
				running = append(running, rec)
			}
		default:
			terminals = append(terminals, rec)
		}
	}

	sort.Slice(active, func(i, j int) bool {
		if active[i].StartedAt.Equal(active[j].StartedAt) {
			return active[i].ID > active[j].ID
		}
		return active[i].StartedAt.After(active[j].StartedAt)
	})
	sort.Slice(running, func(i, j int) bool {
		if running[i].StartedAt.Equal(running[j].StartedAt) {
			return running[i].ID > running[j].ID
		}
		return running[i].StartedAt.After(running[j].StartedAt)
	})

	return active, running, terminals, staleIDs, nil
}

func (s *WorkerSupervisor) recordTerminalHistory(terminals []WorkerRecord, now time.Time) {
	s.mu.Lock()
	defer s.mu.Unlock()

	if len(terminals) == 0 {
		return
	}

	if s.seenTerminals == nil {
		s.seenTerminals = map[string]time.Time{}
	}
	if s.blockedTerminals == nil {
		s.blockedTerminals = map[string]string{}
	}

	for _, rec := range terminals {
		if _, seen := s.seenTerminals[rec.ID]; seen {
			continue
		}
		s.seenTerminals[rec.ID] = now
		if isExpectedTerminalWorker(rec) {
			continue
		}
		if isRestartBlockedWorker(rec) {
			s.blockedTerminals[rec.ID] = firstNonEmpty(
				rec.ReapReason,
				rec.Status,
				rec.LastError,
				rec.Error,
				rec.State,
			)
			continue
		}
		ts := rec.FinishedAt
		if ts.IsZero() {
			ts = rec.StartedAt
		}
		if ts.IsZero() {
			ts = now
		}
		s.restartEvents = append(s.restartEvents, ts)
	}

	s.restartEvents = pruneTimeWindow(s.restartEvents, now, time.Hour)
}

func (s *WorkerSupervisor) stopNewestExcess(running []WorkerRecord, excess int) error {
	if excess <= 0 {
		return nil
	}

	limit := excess
	if len(running) < limit {
		limit = len(running)
	}
	for i := 0; i < limit; i++ {
		if err := s.manager.Stop(running[i].ID); err != nil {
			return err
		}
	}
	return nil
}

func (s *WorkerSupervisor) canStartMore(state WorkerDesiredState, now time.Time) bool {
	s.mu.Lock()
	defer s.mu.Unlock()

	if len(s.blockedTerminals) > 0 {
		return false
	}

	events := pruneTimeWindow(s.restartEvents, now, time.Hour)
	s.restartEvents = events
	if !state.Restart.Enabled {
		return len(events) == 0
	}
	if len(events) == 0 {
		return true
	}
	if len(events) > state.Restart.MaxRestartsPerHour {
		return false
	}
	delay := restartBackoffDelay(state.Restart, len(events))
	last := events[0]
	for _, ts := range events[1:] {
		if ts.After(last) {
			last = ts
		}
	}
	return !now.Before(last.Add(delay))
}

func restartBackoffDelay(policy WorkerRestartPolicy, recentEvents int) time.Duration {
	delay := policy.Backoff.Duration
	if delay <= 0 {
		return 0
	}
	if recentEvents <= 1 {
		if policy.BackoffMax.Duration > 0 && delay > policy.BackoffMax.Duration {
			return policy.BackoffMax.Duration
		}
		return delay
	}

	shift := recentEvents - 1
	for shift > 0 {
		if delay > time.Duration(1<<62) {
			delay = policy.BackoffMax.Duration
			break
		}
		delay *= 2
		shift--
		if policy.BackoffMax.Duration > 0 && delay >= policy.BackoffMax.Duration {
			delay = policy.BackoffMax.Duration
			break
		}
	}
	if policy.BackoffMax.Duration > 0 && delay > policy.BackoffMax.Duration {
		delay = policy.BackoffMax.Duration
	}
	return delay
}

func pruneTimeWindow(times []time.Time, now time.Time, window time.Duration) []time.Time {
	if window <= 0 || len(times) == 0 {
		return append([]time.Time(nil), times...)
	}
	cutoff := now.Add(-window)
	out := make([]time.Time, 0, len(times))
	for _, ts := range times {
		if ts.Before(cutoff) {
			continue
		}
		out = append(out, ts)
	}
	return out
}

func isExpectedTerminalWorker(rec WorkerRecord) bool {
	switch rec.State {
	case "stopped":
		return true
	case "exited":
		switch rec.Status {
		case "success", "no_ready_work":
			return true
		}
	}
	return false
}

func isRestartBlockedWorker(rec WorkerRecord) bool {
	fields := []string{
		rec.ReapReason,
		rec.Status,
		rec.LastError,
		rec.Error,
		rec.State,
	}
	for _, field := range fields {
		lower := strings.ToLower(field)
		if strings.Contains(lower, "operator_attention") ||
			strings.Contains(lower, "dirty_root") ||
			strings.Contains(lower, "dirty-root") ||
			strings.Contains(lower, "dirty root") {
			return true
		}
	}
	return false
}

func firstNonEmpty(values ...string) string {
	for _, v := range values {
		if strings.TrimSpace(v) != "" {
			return v
		}

func countWorkTerminalOutcomes(result *agent.ExecuteBeadLoopResult) (closed, changed, alreadySatisfied, preserved int) {
	for _, attempt := range result.Results {
		switch attempt.Status {
		case agent.ExecuteBeadStatusSuccess:
			closed++
			changed++
		case agent.ExecuteBeadStatusAlreadySatisfied:
			closed++
			alreadySatisfied++
		case agent.ExecuteBeadStatusPreservedNeedsReview:
			preserved++
		}
	}
	if closed == 0 && result.Successes > 0 {
		closed = result.Successes
	}
	return closed, changed, alreadySatisfied, preserved
}

func preservedWorkAttempts(result *agent.ExecuteBeadLoopResult) []agent.ExecuteBeadReport {
	if result == nil {
		return nil
	}
	var out []agent.ExecuteBeadReport
	for _, attempt := range result.Results {
		if attempt.Status == agent.ExecuteBeadStatusPreservedNeedsReview {
			out = append(out, attempt)
		}
	}
	return out
}

func failedWorkAttempts(result *agent.ExecuteBeadLoopResult) []agent.ExecuteBeadReport {
	if result == nil {
		return nil
	}
	var out []agent.ExecuteBeadReport
	for _, attempt := range result.Results {
		switch attempt.Status {
		case agent.ExecuteBeadStatusSuccess,
			agent.ExecuteBeadStatusAlreadySatisfied,
			agent.ExecuteBeadStatusPreservedNeedsReview:
			continue
		default:
			out = append(out, attempt)
		}
	}
	return out
}

func workExitSummary(result *agent.ExecuteBeadLoopResult) string {
	switch result.ExitReason {
	case "drained":
		return "drained current execution-ready queue"
	case "once_complete":
		return "once complete"
	case "budget":
		return "budget reached"
	case "no_progress":
		return "no-progress policy stopped work"
	case "blocked":
		return "blocked waiting for external action"
	case "operator_attention":
		return "operator attention required"
	case "sigint", "sigterm", "context_cancelled":
		return "stopped by signal"
	case "fatal_config":
		return "fatal configuration error"
	case "preflight_failed":
		return "preflight failed"
	case "resource_exhausted":
		return "resource exhausted"
	case "routing_unavailable":
		return "routing unavailable"
	}
	if result.StopCondition != "" {
		return strings.ToLower(strings.ReplaceAll(result.StopCondition, "_", " "))
	}
	return "completed"
}

func writeQueueSnapshotTerminalSummary(w io.Writer, snapshot *agent.QueueSnapshot) {
	if snapshot == nil {
