func (m *WorkerManager) managedWorkerSnapshot(id string, handle *workerHandle) (WorkerRecord, bool) {
	if handle == nil || !handle.managed {
		if handle == nil {
			return WorkerRecord{}, false
		}
		return handle.record, true
	}
	rec, err := m.readRecord(filepath.Join(m.rootDir, id))
	if err != nil || rec.ID == "" {
		return handle.record, true
	}
	if rec.PID == 0 {
		rec.PID = handle.record.PID
	}
	if rec.PGID == 0 {
		rec.PGID = handle.record.PGID
	}
	if rec.StartedAt.IsZero() {
		rec.StartedAt = handle.record.StartedAt
	}
	return rec, true
}

func latestPhaseTimestamp(rec WorkerRecord, fallback time.Time) time.Time {
	if len(rec.RecentPhases) > 0 {
		ts := rec.RecentPhases[len(rec.RecentPhases)-1].TS
		if !ts.IsZero() {
			return ts
		}
	}
	if rec.CurrentAttempt != nil && !rec.CurrentAttempt.StartedAt.IsZero() {
		return rec.CurrentAttempt.StartedAt
	}
	if !rec.StartedAt.IsZero() {
		return rec.StartedAt
	}
	return fallback
}

