func TestManagedWorkerRecordsProcessGroup(t *testing.T) {
	root := t.TempDir()
	setupBeadStoreWithReadyBead(t, root)

	m := NewWorkerManager(root)
	defer m.StopWatchdog()

	m.ManagedWorkerLauncher = func(ctx context.Context, projectRoot, workerID string) (*exec.Cmd, error) {
		_ = ctx
		cmd := exec.Command(os.Args[0],
			"-test.run", "^TestHelperManagedWorkerProcess$",
			"-test.count=1",
			"-test.v",
		)
		cmd.Dir = projectRoot
		cmd.Env = append(os.Environ(),
			managedWorkerHelperEnv+"=1",
			managedWorkerRootEnv+"="+projectRoot,
			managedWorkerIDEnv+"="+workerID,
		)
		return cmd, nil
	}

	record, err := m.StartManagedExecuteLoop(ExecuteLoopWorkerSpec{
		Mode:              "once",
		OpaquePassthrough: true,
	})
	require.NoError(t, err)
	require.NotZero(t, record.PID)
	require.NotZero(t, record.PGID)
	assert.Equal(t, record.PID, record.PGID)

	require.Eventually(t, func() bool {
		return isPIDAlive(record.PID)
	}, 5*time.Second, 25*time.Millisecond)

	shown, err := m.Show(record.ID)
	require.NoError(t, err)
	require.NotZero(t, shown.PID)
	require.NotZero(t, shown.PGID)
	assert.Equal(t, record.PID, shown.PID)
	assert.Equal(t, record.PGID, shown.PGID)

	statusPath := filepath.Join(root, ddxroot.DirName, "workers", record.ID, "status.json")
	data, err := os.ReadFile(statusPath)
	require.NoError(t, err)

	var disk WorkerRecord
	require.NoError(t, json.Unmarshal(data, &disk))
	require.NotZero(t, disk.PID)
	require.NotZero(t, disk.PGID)
	assert.Equal(t, record.PID, disk.PID)
	assert.Equal(t, record.PGID, disk.PGID)

	require.NoError(t, m.Stop(record.ID))
	require.Eventually(t, func() bool {
		return !isPIDAlive(record.PID)
	}, 5*time.Second, 25*time.Millisecond)
}

func TestHelperManagedWorkerProcess(t *testing.T) {
	if os.Getenv(managedWorkerHelperEnv) != "1" {
		t.Skip("not invoked as managed-worker helper subprocess")
	}

	root := os.Getenv(managedWorkerRootEnv)
	workerID := os.Getenv(managedWorkerIDEnv)
	if root == "" || workerID == "" {
		t.Fatal("managed worker helper env vars are required")
	}

	err := RunManagedExecuteLoopWorker(context.Background(), root, workerID, &ManagedExecuteLoopWorkerOptions{
		BeadWorkerFactory: func(store agent.ExecuteBeadLoopStore) *agent.ExecuteBeadWorker {
			return &agent.ExecuteBeadWorker{
				Store: store,
				Executor: agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
					select {
					case <-ctx.Done():
						return agent.ExecuteBeadReport{
							BeadID: beadID,
							Status: agent.ExecuteBeadStatusExecutionFailed,
							Detail: ctx.Err().Error(),
						}, ctx.Err()
					}
				}),
			}
		},
	})
	if err != nil {
		t.Fatalf("managed worker helper failed: %v", err)
	}
}

	if err := os.MkdirAll(m.rootDir, 0o755); err != nil {
		return nil, err
	}
	entries, err := os.ReadDir(m.rootDir)
	if err != nil {
		return nil, err
	}
	var out []WorkerRecord
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		rec, err := m.readRecord(filepath.Join(m.rootDir, entry.Name()))
		if err != nil {
			continue
		}
		if !isWorkerRegistryRecord(rec) {
			continue
		}
		out = append(out, rec)
	}

	type workerSnapshot struct {
		managed bool
		record  WorkerRecord
	}

	// Merge in-memory state for active workers. Managed workers read back the
	// child-written disk record so List can surface the live status.json view.
	m.mu.Lock()
	snapshots := make(map[string]workerSnapshot, len(m.workers))
	for id, handle := range m.workers {
		if handle == nil {
			continue
		}
		snapshots[id] = workerSnapshot{managed: handle.managed, record: handle.record}
	}
	m.mu.Unlock()

	m.mu.Lock()
	for i := range out {
		if snap, ok := snapshots[out[i].ID]; ok {
			if rec, ok := m.managedWorkerSnapshot(out[i].ID, snap.managed, snap.record); ok {
				out[i] = rec
			}
		}
	}
	m.mu.Unlock()

	sort.Slice(out, func(i, j int) bool {
		return out[i].StartedAt.After(out[j].StartedAt)
	})

	// Compute PIDAlive for each record so operators can see liveness at a
	// glance without running prune. This is a syscall per record; it's safe
	// because List() is not on a hot path (workers are long-lived).
	for i := range out {
		if out[i].PID > 0 {
			alive := isPIDAlive(out[i].PID)
			out[i].PIDAlive = &alive
		}
	}

	return out, nil
}

func isWorkerRegistryRecord(rec WorkerRecord) bool {
	return rec.ID != "" || rec.Kind != "" || rec.State != ""
}

func (m *WorkerManager) Show(id string) (WorkerRecord, error) {
	m.mu.Lock()
	if handle, ok := m.workers[id]; ok {
		managed := handle.managed
		rec := handle.record
		m.mu.Unlock()
		if managed {
			if snapshot, ok := m.managedWorkerSnapshot(id, managed, rec); ok {
				return snapshot, nil
			}
		}
		return rec, nil
	}
	m.mu.Unlock()
	return m.readRecord(filepath.Join(m.rootDir, id))
}

// Stop performs a graceful termination of the worker:
//  1. Mark state=stopping and persist so observers see the transition.
//  2. Emit bead.stopped event + release the bead claim (if one is held).
//  3. Send SIGTERM to the worker's process group; escalate to SIGKILL
//     after WatchdogKillGrace if the leader is still alive. Pure-goroutine
//     workers have no PID — ctx cancellation below is the only lever.
//  4. Cancel the worker's context so the loop and in-flight executor exit.
//  5. Mark state=stopped and persist. runWorker preserves this terminal
//     state when it writes its final record.
//
// Stop is idempotent: a second call is a no-op. It returns an error only
// when the worker is unknown to the manager (already exited / never existed).

