	if err := os.MkdirAll(m.rootDir, 0o755); err != nil {
		return WorkerRecord{}, err
	}

	id := "worker-" + time.Now().UTC().Format("20060102T150405") + "-" + randomSuffix(4)
	dir := filepath.Join(m.rootDir, id)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return WorkerRecord{}, err
	}

	specData, _ := json.MarshalIndent(spec, "", "  ")
	if err := os.WriteFile(filepath.Join(dir, "spec.json"), append(specData, '\n'), 0o644); err != nil {
		return WorkerRecord{}, err
	}

	record := buildManagedWorkerRecord(m.rootDir, effectiveRoot, id, spec, 0, time.Now().UTC())
	if err := m.writeRecord(dir, record); err != nil {
		return WorkerRecord{}, err
	}

	launcher := m.ManagedWorkerLauncher
	if launcher == nil {
		launcher = defaultManagedWorkerLauncher
	}
	cmd, err := launcher(context.Background(), effectiveRoot, id)
	if err != nil {
		record.State = "failed"
		record.Status = "failed"
		record.Error = err.Error()
		record.LastError = err.Error()
		record.FinishedAt = time.Now().UTC()
		_ = m.writeRecord(dir, record)
		return WorkerRecord{}, err
	}
	if cmd == nil {
		err = fmt.Errorf("managed worker launcher returned nil command")
		record.State = "failed"
		record.Status = "failed"
		record.Error = err.Error()
		record.LastError = err.Error()
		record.FinishedAt = time.Now().UTC()
		_ = m.writeRecord(dir, record)
		return WorkerRecord{}, err
	}
	if cmd.Dir == "" {
		cmd.Dir = effectiveRoot
	}
	configureManagedWorkerProcessGroup(cmd)

	runtime.LockOSThread()
	err = cmd.Start()
	runtime.UnlockOSThread()
	if err != nil {
		record.State = "failed"
		record.Status = "failed"
		record.Error = err.Error()
		record.LastError = err.Error()
		record.FinishedAt = time.Now().UTC()
		_ = m.writeRecord(dir, record)
		return WorkerRecord{}, err
	}

	pid := cmd.Process.Pid
	record.PID = pid
	record.PGID = pid
	if err := m.writeRecord(dir, record); err != nil {
		terminateProcessGroup(pid, 2*time.Second)
		return WorkerRecord{}, err
	}

	handle := &workerHandle{
		record:       record,
		cancel:       func() {},
		managed:      true,
		progressDone: closedProgressDone(),
		lastPhaseTS:  record.StartedAt,
	}
	m.mu.Lock()
	m.workers[id] = handle
	m.mu.Unlock()

	m.ensureWatchdog()

	go m.waitManagedWorker(cmd, id, dir, handle)

	return record, nil
}

// RunManagedExecuteLoopWorker runs the managed worker entrypoint inside the
// child process. The production child uses real worker infrastructure; tests
// may inject a fake BeadWorkerFactory via opts.
func RunManagedExecuteLoopWorker(ctx context.Context, projectRoot, workerID string, opts *ManagedExecuteLoopWorkerOptions) error {
	if projectRoot == "" {
		return fmt.Errorf("managed worker project root is required")
	}
	if workerID == "" {
		return fmt.Errorf("managed worker id is required")
	}

	m := NewWorkerManager(projectRoot)
	if opts != nil && opts.BeadWorkerFactory != nil {
		m.BeadWorkerFactory = opts.BeadWorkerFactory
	}

	spec, record, handle, eventsFile, err := prepareManagedWorkerRuntime(m, projectRoot, workerID)
	if err != nil {
		return err
	}

	progressCh := make(chan agent.ProgressEvent, 64)
	wakeCh := make(chan struct{}, 1)
	handle.progressCh = progressCh
	handle.wakeCh = wakeCh
	handle.progressDone = make(chan struct{})
	handle.lastPhaseTS = record.StartedAt

	m.mu.Lock()
	m.workers[workerID] = handle
	m.mu.Unlock()

	m.ensureWatchdog()

	go m.drainProgress(workerID, handle, progressCh)
	m.runWorker(ctx, workerID, filepath.Join(m.rootDir, workerID), spec, projectRoot, handle, io.MultiWriter(handle.logBuf, handle.logFile), eventsFile, progressCh)

	return nil
}

func prepareManagedWorkerRuntime(m *WorkerManager, projectRoot, workerID string) (ExecuteLoopWorkerSpec, WorkerRecord, *workerHandle, *os.File, error) {
	dir := filepath.Join(m.rootDir, workerID)

	spec, err := readManagedWorkerSpec(dir, projectRoot)
	if err != nil {
		return ExecuteLoopWorkerSpec{}, WorkerRecord{}, nil, nil, err
	}
	spec.ProjectRoot = projectRoot
	spec.ApplyDefaults()
	if err := spec.Validate(); err != nil {
		return ExecuteLoopWorkerSpec{}, WorkerRecord{}, nil, nil, err
	}

	now := time.Now().UTC()
	rec, err := m.readRecord(dir)
	if err != nil || rec.ID == "" {
		rec = buildManagedWorkerRecord(m.rootDir, projectRoot, workerID, spec, os.Getpid(), now)
	} else {
		rec.ProjectRoot = projectRoot
		rec.Kind = "work"
		rec.State = "running"
		rec.Status = "running"
		rec.Harness = spec.Harness
		rec.Model = spec.Model
		rec.Profile = agent.NormalizeRoutingProfile(spec.Profile)
		rec.Effort = spec.Effort
		rec.Once = executeLoopOnce(spec)
		rec.PollInterval = executeLoopPollInterval(spec).String()
		rec.StdoutPath = relToProject(m.projectRoot, filepath.Join(dir, "worker.log"))
		rec.SpecPath = relToProject(m.projectRoot, filepath.Join(dir, "spec.json"))
		if rec.StartedAt.IsZero() {
			rec.StartedAt = now
		}
		rec.PID = os.Getpid()
		rec.PGID = os.Getpid()
	}

	if rec.Lifecycle == nil {
		rec.Lifecycle = []WorkerLifecycleEvent{{

		terminateProcessGroup(pid, grace)
	}

	// 3. Cancel the goroutine so any in-process code sees context.Canceled.
	if handle.cancel != nil {
		handle.cancel()
	}

	// 4. Flip state=reaped and persist. runWorker may still race to
	//    overwrite this with "exited" when it returns; that's fine — the
	//    bead.reaped event plus released claim are the durable record.
	m.mu.Lock()
	handle.record.State = "reaped"
	handle.record.Status = "reaped"
	handle.record.ReapReason = reason
	if handle.record.FinishedAt.IsZero() {
		handle.record.FinishedAt = now
	}
	if handle.record.LastError == "" {
		handle.record.LastError = fmt.Sprintf("watchdog reaped worker after runtime=%s stalled=%s",
			runtime.Round(time.Second), stalled.Round(time.Second))
	}
	dir := filepath.Join(m.rootDir, id)
	snapshot := handle.record
	m.mu.Unlock()

	_ = m.writeRecord(dir, snapshot)
}

func (m *WorkerManager) Logs(id string) (string, string, error) {
	m.mu.Lock()
	if handle, ok := m.workers[id]; ok {
		managed := handle.managed
		logBuf := handle.logBuf
		rec := handle.record
		m.mu.Unlock()
		if managed {
			snapshot, ok := m.managedWorkerSnapshot(id, managed, rec)
			if !ok {
				return "", "", nil
			}
			if snapshot.StdoutPath == "" {
				return "", "", nil
			}
			data, err := os.ReadFile(filepath.Join(m.projectRoot, snapshot.StdoutPath))
			if err != nil {
				return "", "", err
			}
			return string(data), "", nil
		}
		if logBuf == nil {
			return "", "", nil
		}
		return logBuf.String(), "", nil
	}
	m.mu.Unlock()

	// Fall back to reading from disk for completed workers
	rec, err := m.Show(id)
	if err != nil {
		return "", "", err
	}
	if rec.StdoutPath == "" {
		return "", "", nil
	}
	data, err := os.ReadFile(filepath.Join(m.projectRoot, rec.StdoutPath))
	if err != nil {
		return "", "", err
	}
	return string(data), "", nil
}

// drainProgress reads ProgressEvents from ch and:
//  1. Updates the WorkerRecord's CurrentAttempt, RecentPhases, and LastAttempt fields.
//  2. Broadcasts each event to all active SSE subscribers for the worker.
//
// It runs as a goroutine alongside runWorker; it exits when ch is closed.
func (m *WorkerManager) drainProgress(workerID string, handle *workerHandle, ch <-chan agent.ProgressEvent) {
	const maxRecentPhases = 20
	for evt := range ch {
		m.mu.Lock()
		rec := handle.record

		// Substate signals (ddx-dc157075 AC #5). loop.idle marks the worker as
		// "idle" without disturbing CurrentAttempt; loop.active clears it when
		// the loop picks up the next candidate. These are not real attempt
		// phases, so they bypass the normal RecentPhases / CurrentAttempt path.
		switch evt.Phase {
		case "loop.idle":
			rec.Substate = "idle"
			handle.record = rec
			m.mu.Unlock()
			continue
		case "loop.active":
			rec.Substate = ""
			handle.record = rec
			m.mu.Unlock()
			continue
		}

		if !evt.Heartbeat {
			// Phase-transition: record in RecentPhases (capped at maxRecentPhases)
			rec.RecentPhases = append(rec.RecentPhases, PhaseTransition{
				Phase:    evt.Phase,
				TS:       evt.TS,
				PhaseSeq: evt.PhaseSeq,
			})
			if len(rec.RecentPhases) > maxRecentPhases {
				rec.RecentPhases = rec.RecentPhases[len(rec.RecentPhases)-maxRecentPhases:]
			}
			// Stamp lastPhaseTS so the watchdog can detect stalled attempts.
			handle.lastPhaseTS = evt.TS
		}

		if terminalPhases[evt.Phase] {
			// Increment live counters so Show() reflects progress before the
			// loop exits. runWorker will overwrite these with authoritative
			// loopResult values after progressDone is signalled, which is the
			// same value — so no double-counting occurs.
			rec.Attempts++
			if evt.Phase == "done" {
				rec.Successes++
			} else {
				rec.Failures++
			}

			// Move CurrentAttempt → LastAttempt
			if rec.CurrentAttempt != nil {
				rec.LastAttempt = &LastAttemptInfo{
					AttemptID: rec.CurrentAttempt.AttemptID,
					BeadID:    rec.CurrentAttempt.BeadID,
					Phase:     evt.Phase,
					StartedAt: rec.CurrentAttempt.StartedAt,
					EndedAt:   evt.TS,
					ElapsedMS: evt.ElapsedMS,
				}
			}
			rec.CurrentAttempt = nil
		} else {
			// Update or initialise CurrentAttempt
			if rec.CurrentAttempt == nil {
				rec.CurrentAttempt = &CurrentAttemptInfo{
					AttemptID: evt.AttemptID,
					BeadID:    evt.BeadID,
					StartedAt: evt.TS,
				}
			}
			rec.CurrentAttempt.AttemptID = evt.AttemptID
			rec.CurrentAttempt.BeadID = evt.BeadID
			rec.CurrentAttempt.Phase = evt.Phase
			rec.CurrentAttempt.PhaseSeq = evt.PhaseSeq
			rec.CurrentAttempt.ElapsedMS = evt.ElapsedMS
			if evt.Harness != "" {
				rec.CurrentAttempt.Harness = evt.Harness
			}
			if evt.Model != "" {
				rec.CurrentAttempt.Model = evt.Model
			}
			if evt.Profile != "" {
				rec.CurrentAttempt.Profile = evt.Profile
			}
		}

		handle.record = rec

		// Broadcast to SSE subscribers (non-blocking; slow subscribers are dropped)
		subs := handle.progressSubs
		m.mu.Unlock()

		for _, sub := range subs {
			select {
			case sub <- evt:
			default:
				// Subscriber channel full — skip rather than block
			}
		}
	}

	// Channel closed: clear CurrentAttempt if still set (worker exited)
	m.mu.Lock()
	if handle.record.CurrentAttempt != nil {
		handle.record.CurrentAttempt = nil
	}
	// Close and remove all subscriber channels
	for _, sub := range handle.progressSubs {
		close(sub)
	}
	handle.progressSubs = nil
	m.mu.Unlock()

	// Signal that no further events will arrive
	if handle.progressDone != nil {
		close(handle.progressDone)
	}
}

// SubscribeProgress returns a channel that receives ProgressEvents for the
// given worker, plus an unsubscribe function. If the worker is not active or
// has already finished, the returned channel is pre-closed so SSE handlers
// can detect idle/done state immediately.
func (m *WorkerManager) SubscribeProgress(workerID string) (<-chan agent.ProgressEvent, func()) {
	m.mu.Lock()
	defer m.mu.Unlock()

	handle, ok := m.workers[workerID]
	if !ok {
		// Worker never started or was never registered
		ch := make(chan agent.ProgressEvent)
		close(ch)
		return ch, func() {}
	}

	if handle.managed {
		ch := make(chan agent.ProgressEvent)
		close(ch)
		return ch, func() {}

		rec.Lifecycle = []WorkerLifecycleEvent{{
			Action:    "start",
			Actor:     "local-operator",
			Timestamp: rec.StartedAt,
			Detail:    lifecycleStartDetail(spec),
		}}
	}

	logPath := filepath.Join(dir, "worker.log")
	logFile, err := os.OpenFile(logPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o644)
	if err != nil {
		return ExecuteLoopWorkerSpec{}, WorkerRecord{}, nil, nil, err
	}

	eventsPath := filepath.Join(dir, "worker-events.jsonl")
	eventsFile, eventsErr := os.OpenFile(eventsPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o644)
	if eventsErr != nil {
		eventsFile = nil
	}

	handle := &workerHandle{
		record:  rec,
		cancel:  func() {},
		logBuf:  &bytes.Buffer{},
		logFile: logFile,
		managed: true,
	}

	if err := m.writeRecord(dir, rec); err != nil {
		_ = logFile.Close()
		if eventsFile != nil {
			_ = eventsFile.Close()
		}
		return ExecuteLoopWorkerSpec{}, WorkerRecord{}, nil, nil, err
	}

	return spec, rec, handle, eventsFile, nil
}

func readManagedWorkerSpec(dir, projectRoot string) (ExecuteLoopWorkerSpec, error) {
	data, err := os.ReadFile(filepath.Join(dir, "spec.json"))
	if err != nil {
		return ExecuteLoopWorkerSpec{}, err
	}
	var spec ExecuteLoopWorkerSpec
	if err := json.Unmarshal(data, &spec); err != nil {
		return ExecuteLoopWorkerSpec{}, err
	}
	if spec.ProjectRoot == "" {
		spec.ProjectRoot = projectRoot
	}
	return spec, nil
}

func buildManagedWorkerRecord(rootDir, projectRoot, id string, spec ExecuteLoopWorkerSpec, pid int, startedAt time.Time) WorkerRecord {
	logPath := filepath.Join(rootDir, id, "worker.log")
	specPath := filepath.Join(rootDir, id, "spec.json")
	rec := WorkerRecord{
		ID:           id,
		Kind:         "work",
		State:        "running",
		Status:       "running",
		ProjectRoot:  projectRoot,
		Harness:      spec.Harness,
		Model:        spec.Model,
		Profile:      agent.NormalizeRoutingProfile(spec.Profile),
		Effort:       spec.Effort,
		Once:         executeLoopOnce(spec),
		PollInterval: executeLoopPollInterval(spec).String(),
		StdoutPath:   relToProject(projectRoot, logPath),
		SpecPath:     relToProject(projectRoot, specPath),
		StartedAt:    startedAt,
		PID:          pid,
		PGID:         pid,
	}
	rec.Lifecycle = append(rec.Lifecycle, WorkerLifecycleEvent{
		Action:    "start",
		Actor:     "local-operator",
		Timestamp: startedAt,
		Detail:    lifecycleStartDetail(spec),
	})
	return rec
}

func closedProgressDone() chan struct{} {
	ch := make(chan struct{})
	close(ch)
	return ch
}

func isTestBinaryExecutable() bool {
	exe, err := os.Executable()
	if err != nil {
		return false
	}
	base := filepath.Base(exe)
	return strings.HasSuffix(base, ".test") || strings.HasSuffix(base, ".test.exe")
}

func defaultManagedWorkerLauncher(ctx context.Context, projectRoot, workerID string) (*exec.Cmd, error) {
	if ctx == nil {
		ctx = context.Background()
	}
	exe, err := os.Executable()
	if err != nil {
		return nil, err
	}
	cmd := exec.CommandContext(ctx, exe, "work", "--server-managed", workerID, "--project", projectRoot)
	cmd.Dir = projectRoot
	return cmd, nil
}

func (m *WorkerManager) waitManagedWorker(cmd *exec.Cmd, id, dir string, handle *workerHandle) {
	err := cmd.Wait()

	rec, readErr := m.readRecord(dir)
	if readErr == nil && rec.ID != "" {
		m.mu.Lock()
		if handle != nil {
			handle.record = rec
		}
		m.mu.Unlock()
		if rec.State == "stopped" || rec.State == "reaped" || rec.FinishedAt.IsZero() == false {
			return
		}
	}

	if err == nil {
		err = fmt.Errorf("managed worker exited without a terminal status record")
	}

	now := time.Now().UTC()
	m.mu.Lock()
	if handle != nil {
		rec = handle.record
	}
	if rec.ID == "" {
		rec = WorkerRecord{ID: id, Kind: "work", ProjectRoot: m.projectRoot, StartedAt: now}
	}
	rec.State = "failed"
	rec.Status = "failed"
	if rec.FinishedAt.IsZero() {
		rec.FinishedAt = now
	}
	rec.Error = err.Error()
	rec.LastError = err.Error()
	if handle != nil {
		handle.record = rec
	}
	m.mu.Unlock()

	_ = m.writeRecord(dir, rec)
}

func (m *WorkerManager) managedWorkerSnapshot(id string, managed bool, fallback WorkerRecord) (WorkerRecord, bool) {
	if !managed {
		return fallback, true
	}
	rec, err := m.readRecord(filepath.Join(m.rootDir, id))
	if err != nil || rec.ID == "" {
		return fallback, true
	}
	if rec.PID == 0 {
		rec.PID = fallback.PID
	}
	if rec.PGID == 0 {
		rec.PGID = fallback.PGID
	}
	if rec.StartedAt.IsZero() {
		rec.StartedAt = fallback.StartedAt
	}
	return rec, true
}

func latestPhaseTimestamp(rec WorkerRecord, fallback time.Time) time.Time {
	if len(rec.RecentPhases) > 0 {
		ts := rec.RecentPhases[len(rec.RecentPhases)-1].TS
		if !ts.IsZero() {
			return ts
		}
	}
	if rec.CurrentAttempt != nil && !rec.CurrentAttempt.StartedAt.IsZero() {
		return rec.CurrentAttempt.StartedAt
	}
	if !rec.StartedAt.IsZero() {
		return rec.StartedAt
	}
	return fallback
}

